1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const BLOCK_OF_3_BASE_PREMIUM = 60;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
23	type Step = { op: "quote"; items: Item[] };
24	type Customer = { yearsWithMHPCO: number };
25	type Scenario = { customer: Customer; steps: Step[] };
26	type QuoteResult = { premium: number };
27	
28	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
29	
30	const itemSurcharges = (item: Item): number => {
31	  const base = BASE_PREMIUM[item.type];
32	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
33	  const highEnchSurcharge =
34	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
35	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
36	      : 0;
37	  return curseSurcharge + highEnchSurcharge;
38	};
39	
40	const countByType = (items: Item[]): Map<string, number> => {
41	  const counts = new Map<string, number>();
42	  for (const item of items) {
43	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
44	  }
45	  return counts;
46	};
47	
48	const componentGroupBase = (type: string, count: number): number =>
49	  count === 3 ? BLOCK_OF_3_BASE_PREMIUM : count * BASE_PREMIUM[type];
50	
51	const policyBase = (items: Item[]): number => {
52	  const components = items.filter(isComponent);
53	  const mainItems = items.filter((item) => !isComponent(item));
54	  const mainBase = mainItems.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
55	  const componentBase = Array.from(countByType(components)).reduce(
56	    (sum, [type, count]) => sum + componentGroupBase(type, count),
57	    0,
58	  );
59	  return mainBase + componentBase;
60	};
61	
62	const sumItemSurcharges = (items: Item[]): number =>
63	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
64	
65	const loyaltyDiscount = (customer: Customer, base: number): number =>
66	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
67	
68	const quoteStep = (step: Step, customer: Customer, isFollowUp: boolean): QuoteResult => {
69	  const base = policyBase(step.items);
70	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
71	  const followUpDiscount = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
72	  const premium =
73	    base +
74	    firstInsurance -
75	    loyaltyDiscount(customer, base) -
76	    followUpDiscount +
77	    sumItemSurcharges(step.items) +
78	    PROCESSING_FEE;
79	  return { premium: Math.ceil(premium) };
80	};
81	
82	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
83	  results: scenario.steps.map((step, index) => quoteStep(step, scenario.customer, index > 0)),
84	});
